def before_save(doc, method):
    if doc.status == "In Progress":
        required = {
            "Tender ID": doc.tender_id,
            "Product Name": doc.title,
            "District": doc.district,
            "Vanue": doc.vanue,
            "Consignee Name": doc.consignee_name,
            "Issue Date": doc.issue_date,
            "Due Date": doc.due_date,
            "Estimated Value": doc.estimated_value,
            "Supplier Name": doc.supplier_name,
            "EMD": doc.emd,
            "GEM Product Link": doc.gem_product_link,
            "Product Authorization No": doc.product_authorization_no,
        }
        missing = [k for k, v in required.items() if not v or v == 0]
        if missing:
            frappe.throw(
                f"In Progress માટે આ fields ભરો: <b>{', '.join(missing)}</b>"
            )

    if doc.status == "Submitted":
        if not doc.tender_documents:
            frappe.throw("Status Submitted કરતા પહેલા Tender Documents upload કરો.")
